                      <div className="absolute -left-[27px] top-[14px]">
                        <motion.div 
                          className={`absolute inset-0 rounded-full ${style.bg}`}
                          initial={{ scale: 0.5, opacity: 1 }}
                          animate={{ scale: 2.5, opacity: 0 }}
                          transition={{ duration: 1.5, repeat: Infinity }}
