"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export interface SingularityButtonProps {
  text?: string;
  onClick?: () => void;
    className?: string;
}

export const SingularityButton = React.forwardRef<any, SingularityButtonProps>(({ className, text = "INITIALIZE SINGULARITY", onClick, ...props }, ref) => {
        const [isImploding, setIsImploding] = useState(false);
        const [isExploding, setIsExploding] = useState(false);
        const canvasRef = useRef<HTMLCanvasElement>(null);

        // Particle System
        useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        let width = canvas.width;
        let height = canvas.height;
        let particles: Particle[] = [];
        let animationFrameId: number;

        class Particle {
          x: number;
          y: number;
          angle: number;
          radius: number;
          speed: number;
          distSq: number;
          size: number;

          constructor() {
            this.angle = Math.random() * Math.PI * 2;
            this.radius = Math.random() * 100 + 40;
            this.x = width / 2 + Math.cos(this.angle) * this.radius;
            this.y = height / 2 + Math.sin(this.angle) * this.radius;
            this.speed = Math.random() * 0.02 + 0.005;
            this.distSq = 0;
            this.size = Math.random() * 1.5 + 0.5;
          }

          update(imploding: boolean) {
            if (imploding) {
              // Spirals toward center quickly
              this.radius *= 0.85;
              this.speed += 0.05;
            }

            this.angle += this.speed;
            this.x = width / 2 + Math.cos(this.angle) * this.radius;
            this.y = height / 2 + Math.sin(this.angle) * this.radius;

            // Reset if too far or too close
            if (this.radius < 2) {
              this.angle = Math.random() * Math.PI * 2;
              this.radius = Math.random() * 100 + 100;
            }
          }

          draw() {
            if (!ctx) return;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(200, 220, 255, ${Math.min(1, 20 / Math.max(1, this.radius))})`;
            ctx.fill();
          }
        }

        const initParticles = () => {
          particles = [];
          for (let i = 0; i < 60; i++) {
            particles.push(new Particle());
          }
        };

        const animate = () => {
          ctx.clearRect(0, 0, width, height);

          // Draw subtle event horizon glow
          const gradient = ctx.createRadialGradient(
            width / 2, height / 2, 0,
            width / 2, height / 2, width / 2
          );
          gradient.addColorStop(0, "rgba(0, 0, 0, 1)");
          gradient.addColorStop(0.3, "rgba(20, 0, 40, 0.4)");
          gradient.addColorStop(1, "rgba(0, 0, 0, 0)");
          ctx.fillStyle = gradient;
          ctx.fillRect(0, 0, width, height);

          particles.forEach((p) => {
            p.update(isImploding);
            p.draw();
          });

          animationFrameId = requestAnimationFrame(animate);
        };

        initParticles();
        animate();

        return () => {
          cancelAnimationFrame(animationFrameId);
        };
        }, [isImploding]);

        const handleClick = () => {
        if (isImploding || isExploding) return;

        setIsImploding(true);

        // Sequence
        setTimeout(() => {
          setIsImploding(false);
          setIsExploding(true);
          if (onClick) onClick();

          setTimeout(() => {
            setIsExploding(false);
          }, 1000);
        }, 1500); // Implosion duration
