        if (!isDragging) return;
        setIsDragging(false);

        if (currentPos.x > SWIPE_THRESHOLD) {
          triggerSwipeOut('right');
        } else if (currentPos.x < -SWIPE_THRESHOLD) {
          triggerSwipeOut('left');
        } else {
          // Spring back to center
          setCurrentPos({ x: 0, y: 0 });
        }
