        setIsAnimatingOut(true);
        setSwipeDirection(direction);
        // Move card offscreen
        setCurrentPos({
          x: direction === 'right' ? window.innerWidth : -window.innerWidth,
          y: currentPos.y + (direction === 'right' ? 100 : -100),
