                {/* Background Glow */}
                <motion.div 
                   initial={{ opacity: 0 }}
                   animate={{ opacity: 1 }}
                   className="absolute inset-0 opacity-40"
                   style={{ backgroundColor: `${secondaryColor}22` }}
