        { id: "share", icon: <Share2 size={18} />, label: "Share", onClick: () => {}, color: "text-purple-400" },
        { id: "delete", icon: <Trash2 size={18} />, label: "Delete", onClick: () => {}, color: "text-red-400" },
        ];

        const displayActions = actions || defaultActions;

