                              transition={{ duration: 2, repeat: Infinity }}
                            />
                          )}
                          <span className="relative z-10">{dayNum}</span>
                        </motion.button>
                      );
                    })}
                  </div>
                </motion.div>
              </div>
            )}
          </AnimatePresence>
        </div>
        );
        });

