    const cy = rect.top + rect.height / 2;

    const angle = Math.atan2(e.clientY - cy, e.clientX - cx) * (180 / Math.PI);

    if (angle >= -45 && angle < 45) return "right";
    if (angle >= 45 && angle < 135) return "bottom";
    if (angle >= -135 && angle < -45) return "top";
    return "left";
  }, []);

  const directionToTransform: Record<Direction, { x; y }> = {
    top,
    bottom,
    left,
    right,
  };

  const handleMouseEnter = (e) => {
    setDirection(getDirection(e));
    setIsHovered(true);
  };

  const handleMouseLeave = (e) => {
    setDirection(getDirection(e));
    setIsHovered(false);
  };

  return (
    <div
      ref={(node) => {
        (containerRef.MutableRefObject<HTMLDivElement | null>).current = node;
        if (typeof ref === "function") ref(node);
        else if (ref) (ref.MutableRefObject<HTMLDivElement | null>).current = node;
      }}
      {...props}
      className={cn(
        "relative overflow-hidden rounded-2xl group cursor-pointer",
        className
      )}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      {/* Base Content */}
      <div className="relative z-0">{children}</div>

      {/* Direction-Aware Overlay */}

        {isHovered && (
          <motion.div
            className="absolute inset-0 z-10 bg-black/70 backdrop-blur-sm flex items-center justify-center"
            initial={directionToTransform[direction]}
            animate={{ x: "0%", y: "0%" }}
            exit={directionToTransform[direction]}
            transition={HOVER_SPRING}
          >
            {overlay}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});

DirectionAwareHover.displayName = "DirectionAwareHover";

