          {/* Animated Beam Pulse */}
          <motion.path
            d={path}
            stroke={`url(#beam-pulse)`}
            strokeWidth="3"
            fill="none"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: [0, 1], opacity: [0, 1, 0] }}
            transition={{
              duration: 2,
              repeat: Infinity,
              delay: i * 0.5,
              ease: "easeInOut",
            }}
          />
        </React.Fragment>
      ))}
    </svg>
  );
};

