                 ))}
               </div>

               {/* Matrix Cells */}
               {activeData.map((row, rIdx) => (
                 <div key={rIdx} className="flex gap-2 h-12">
                   {row.map((val, cIdx) => (
                     <motion.div 
                       key={`${rIdx}-${cIdx}`}
                       initial={{ opacity: 0, scale: 0.5 }}
                       whileInView={{ opacity: 1, scale: 1 }}
