export const NebulaPortalNav = React.forwardRef<any, NebulaPortalNavProps>(({ items, activeId: controlledActiveId, onChange, className = '', ...props }, ref) => {
        const [internalActiveId, setInternalActiveId] = useState(items[0]?.id);
