                  <div className="flex items-center gap-3 px-4 py-3 border-b border-white/5"><SearchIcon size={18} className="text-zinc-500" /><input ref={handleRef} value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Type to search..." className="flex-1 bg-transparent text-white text-sm outline-none placeholder:text-zinc-600" />{query && <button onClick={() => setQuery("")} className="text-zinc-500 hover:text-white cursor-pointer"><X size={15} /></button>}</div>
                  <div className="max-h-64 overflow-y-auto py-2">
