                    <span className="relative z-20 font-medium tracking-wide">
                      {item.label}
                    </span>

                    {/* Fluid Hover Pill */}
                    <AnimatePresence>
                      {isHovered && (
                        <motion.div
                          layoutId="fluid-sidebar-hover"
                          className="absolute inset-0 -z-10 rounded-2xl bg-white/5 shadow-[inset_0_1px_1px_rgba(255,255,255,0.1)]"
