"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion, useMotionValue, useTransform, animate } from "framer-motion";
import { cn } from "@/lib/utils";

  max?;
  defaultValue?;
  onChange?: (value) => void;
    className?;
}

export const ElasticSlider = React.forwardRef<any, ElasticSliderProps>(({ className, min = 0, max = 100, defaultValue = 50, onChange, ...props }, ref) => {
        const containerRef = useRef(null);
        const [isDragging, setIsDragging] = useState(false);
        const [containerWidth, setContainerWidth] = useState(0);

        // Motion values for thumb and SVG path
        const x = useMotionValue(0);
        const pathY = useMotionValue(0); // Y pull of the elastic line

        useEffect(() => {
        if (containerRef.current) {
          const width = containerRef.current.getBoundingClientRect().width;
          setContainerWidth(width);
          // Set initial position
          const initialPercent = (defaultValue - min) / (max - min);
          x.set(width * initialPercent);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
        }, [containerRef]);

        // Calculate value based on x position
        const percentage = useTransform(x, [0, containerWidth || 1], [0, 100]);
        const value = useTransform(percentage, (p) => {
        const val = min + (p / 100) * (max - min);
        return Math.max(min, Math.min(max, Math.round(val)));
        });

        // The SVG path draws a straight line, but curves down/up when dragged
        const svgPath = useTransform([x, pathY], ([latestX, latestY]) => {
        const width = containerWidth || 300;
        const cx = latestX;
        const cy = latestY;

        // Q is quadratic bezier: start, control point (cx, cy), end
        // To make it look elastic, the curve only happens heavily near the thumb
        return `M 0 20 Q ${cx} ${20 + cy * 2} ${width} 20`;
        });

        const handleDragStart = () => {
        setIsDragging(true);
        };

        const handleDrag = (_event, info) => {
        // Pull the string down/up based on vertical drag velocity, bounded loosely
        const dragY = Math.max(-30, Math.min(30, info.offset.y));
        pathY.set(dragY);
        onChange?.(value.get());
        };

        const handleDragEnd = () => {
        setIsDragging(false);
        onChange?.(value.get());
        // Snap the string back to center like a rubber band
        animate(pathY, 0, { type: "spring", stiffness: 500, damping: 10 });
        };

        return (
        <div ref={ref} {...props} className={cn(className)} 
          ref={containerRef}
          className="relative w-full max-w-md h-40 flex items-center justify-center p-6"
        >
          {/* Dynamic Tooltip following thumb */}
          <motion.div
            className="absolute top-0 flex flex-col items-center pointer-events-none"
            style={{ x }}
          >
            <motion.div
              animate={{
                y: isDragging ? -10 : 0,
                scale: isDragging ? 1 : 0.8,
                opacity: isDragging ? 1 : 0,
              }}
              className="bg-pink-500 text-white font-bold text-sm px-3 py-1 rounded-full shadow-lg relative"
            >
              {value}
              {/* Tooltip triangle */}
              <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-4 border-r-4 border-t-4 border-transparent border-t-pink-500" />
            </motion.div>
          </motion.div>

          {/* Elastic SVG Line */}
          <svg className="absolute w-full h-10 top-1/2 -translate-y-1/2 overflow-visible pointer-events-none">
            {/* Track Track */}
            <motion.path
              d={svgPath}
              fill="none"
              stroke="rgba(255, 255, 255, 0.1)"
              strokeWidth="4"
              strokeLinecap="round"
            />
            {/* Active Track Overlay (clipped to thumb position using complex SVG could work, but easy hack is gradient) */}
            <motion.path
              d={svgPath}
              fill="none"
              stroke="url(#gradient)"
              strokeWidth="4"
              strokeLinecap="round"
              style={{ pathLength: percentage }}
            />
            <defs>
              <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#ec4899" />
                <stop offset="100%" stopColor="#a855f7" />
              </linearGradient>
            </defs>
          </svg>

          {/* Draggable Thumb */}
          <motion.div
            drag="x"
            dragConstraints={containerRef}
            dragElastic={0}
            dragMomentum={false}
            onDragStart={handleDragStart}
            onDrag={handleDrag}
            onDragEnd={handleDragEnd}
            style={{ x }}
            className="absolute left-0 w-8 h-8 -ml-4 rounded-full bg-white shadow-[0_0_20px_rgba(236,72,153,0.5)] cursor-grab active:cursor-grabbing flex items-center justify-center z-10"
          >
            <motion.div
              animate={{ scale: isDragging ? 0 : 1 }}
              className="w-3 h-3 rounded-full bg-pink-500"
            />
          </motion.div>
        </div>
        );
        });

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Share2, X, Code as Code2, Globe as Facebook, 
  Briefcase as Briefcase, Camera as Instagram, Video as Youtube, MessageCircle 
} from "lucide-react";
import { cn } from "../utils";
import { useSpatialAudio } from "../hooks";

interface SocialItem {
  id: string;
  icon: React.ElementType;
  label: string;
  color: string;
  href: string;
}

const DEFAULT_ITEMS: SocialItem[] = [
  { id: "x", icon: MessageCircle, label: "X", color: "#000000", href: "#" },
  { id: "facebook", icon: Facebook, label: "Facebook", color: "#1877f2", href: "#" },
  { id: "linkedin", icon: Briefcase, label: "LinkedIn", color: "#0077b5", href: "#" },
  { id: "instagram", icon: Instagram, label: "Instagram", color: "#e4405f", href: "#" },
  { id: "github", icon: Code2, label: "GitHub", color: "#333333", href: "#" },
  { id: "whatsapp", icon: MessageCircle, label: "WhatsApp", color: "#25d366", href: "#" },
  { id: "youtube", icon: Youtube, label: "YouTube", color: "#ff0000", href: "#" },
];

interface CosmicRadialShareMenuProps {
  items?: SocialItem[];
  radius?: number;
  className?: string;
}

/**
 * A "God-Tier" Radial Social Menu (#261).
 * Features:
 * - Centrifugal Spiral Expansion: Icons fly out in a spiral motion.
 * - Continuous Orbital Rotation: The ring slowly orbits the center when open.
 * - Brand-Adaptive Aura Glow: Each icon radiates its identity in a soft volumetric glow.
 * - Liquid Morph Core: The share icon liquid-morphs into a Close (X) icon.
 * - Auto-Close Logic: Implodes back into the center once a destination is selected.
 */
export const CosmicRadialShareMenu = ({
  items = DEFAULT_ITEMS,
  radius = 120,
  className,
}: CosmicRadialShareMenuProps) => {
  const [isOpen, setIsOpen] = useState(false);

  const { play: playWhoosh } = useSpatialAudio({
    enabled: true,
    url: "https://assets.mixkit.co/active_storage/sfx/2571/2571-preview.mp3", // Orbital whoosh/click
  });

  const toggleMenu = () => {
    setIsOpen(!isOpen);
    playWhoosh();
  };

  const handleItemClick = (href: string) => {
    setIsOpen(false);
    playWhoosh();
    // In a real app, window.open(href, '_blank') or similar would happen here
    console.log(`Navigating to ${href}`);
  };

  return (
    <div className={cn("relative flex items-center justify-center w-[350px] h-[350px]", className)}>
      {/* Central Trigger Button */}
      <motion.button
        onClick={toggleMenu}
        className="relative z-50 w-16 h-16 rounded-full bg-white flex items-center justify-center shadow-[0_10px_30px_rgba(0,0,0,0.1)] active:scale-90 transition-transform outline-none"
      >
        <AnimatePresence mode="wait">
          {isOpen ? (
            <motion.div
              key="close"
              initial={{ rotate: -90, scale: 0 }}
              animate={{ rotate: 0, scale: 1 }}
              exit={{ rotate: 90, scale: 0 }}
            >
              <X size={28} className="text-zinc-900" />
            </motion.div>
          ) : (
            <motion.div
              key="share"
              initial={{ rotate: 90, scale: 0 }}
              animate={{ rotate: 0, scale: 1 }}
              exit={{ rotate: -90, scale: 0 }}
            >
              <Share2 size={28} className="text-zinc-900" />
            </motion.div>
          )}
        </AnimatePresence>

        {/* Decorative inner ring */}
        <div className="absolute inset-1 rounded-full border border-black/5 pointer-events-none" />
      </motion.button>

      {/* The Orbital Ring */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <AnimatePresence>
          {isOpen && (
            <motion.div
              initial={{ opacity: 0, rotate: -45 }}
              animate={{ opacity: 1, rotate: 0 }}
              exit={{ opacity: 0, rotate: 45 }}
              className="relative w-full h-full"
            >
              {/* Continuous Slow Orbital Rotation Wrapper */}
              <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 40, repeat: Infinity, ease: "linear" }}
                className="w-full h-full relative"
              >
                {items.map((item, index) => {
                  const angle = (index / items.length) * (2 * Math.PI);
                  const x = Math.cos(angle) * radius;
                  const y = Math.sin(angle) * radius;

                  return (
                    <motion.div
                      key={item.id}
                      initial={{ scale: 0, x: 0, y: 0 }}
                      animate={{ 
                        scale: 1, 
                        x, 
                        y,
                      }}
                      exit={{ scale: 0, x: 0, y: 0 }}
                      transition={{ 
                        type: "spring", 
                        stiffness: 260, 
                        damping: 20,
                        delay: index * 0.05 
                      }}
                      className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto"
                    >
                      <button
                        onClick={() => handleItemClick(item.href)}
                        className="group relative w-12 h-12 rounded-full bg-white flex items-center justify-center shadow-lg hover:scale-110 active:scale-95 transition-all outline-none"
                      >
                        {/* Brand Aura Glow */}
                        <div 
                          className="absolute inset-0 rounded-full opacity-0 group-hover:opacity-40 blur-md transition-opacity"
                          style={{ backgroundColor: item.color }}
                        />

                        {/* Icon - Counter-rotating to stay upright */}
                        <motion.div
                           animate={{ rotate: -360 }}
                           transition={{ duration: 40, repeat: Infinity, ease: "linear" }}
                        >
                          <item.icon 
                            size={20} 
                            strokeWidth={2.5}
                            style={{ color: item.color }} 
                          />
                        </motion.div>

                        {/* Label Tooltip */}
                        <div className="absolute -bottom-8 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap text-[10px] font-bold uppercase tracking-widest text-white bg-black/80 px-2 py-1 rounded-md">
                          {item.label}
                        </div>
                      </button>
                    </motion.div>
                  );
                })}
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Decorative Blur Orbs */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 z-0 bg-black/5 backdrop-blur-sm rounded-full pointer-events-none"
          />
        )}
      </AnimatePresence>
    </div>
  );
};

