  ({ className, items = defaultItems, ...props }, ref) => {
    // 5 layers (index 0 is bottom shadow, index 4 is the top face)
    const layers = [0, 1, 2, 3, 4];

    return (
      <div
        ref={ref}
        className={cn("flex flex-wrap items-center justify-center gap-12 pt-20 pb-16 perspective-[1000px]", className)}
        {...props}
      >
        {items.map((item) => (
          <motion.div
            key={item.id}
            className="relative w-40 h-16 group cursor-pointer"
            style={{
              // This is the core CSS technique perfectly adapted for Framer
              transform: "rotate(-25deg) skew(25deg)",
              transformStyle: "preserve-3d",
            }}
            initial="rest"
            whileHover="hovered"
            whileTap={{ scale: 0.95 }}
          >
            {layers.map((layerIndex) => {
              const isTop = layerIndex === 4;
              const isBottom = layerIndex === 0;

              return (
                <motion.div
                  key={layerIndex}
                  className={cn(
                    "absolute inset-0 flex items-center justify-center gap-3 transition-colors duration-300",
                    isTop ? "bg-white text-zinc-600 border border-zinc-200" : "bg-white border-zinc-300 border-l border-b",
                    isBottom && "bg-black/10 blur-[2px] border-none"
                  )}
                  style={{
                    zIndex: layerIndex,
                    // Slightly darken the middle layers to create a 3D depth illusion
                    opacity: isTop ? 1 : isBottom ? 0.4 : 1 - (4 - layerIndex) * 0.1,
                  }}
                  variants={{
                    rest: {
                      x: 0,
                      y: 0,
                      backgroundColor: isTop ? "#ffffff" : isBottom ? "transparent" : "#f4f4f5",
                      color: "#52525b", // zinc-600
                    },
                    hovered: {
                      // Move top layers up and left (negative x and y)
                      x: isBottom ? 0 : layerIndex * -12,
                      y: isBottom ? 0 : layerIndex * -12,
                      // The top layer gets the brand color
                      backgroundColor: isTop
                        ? item.color
                        : isBottom
                        ? "transparent"
                        : `${item.color}80`, // transparent version of brand color for depth
                      color: isTop ? "#ffffff" : "transparent",
                      boxShadow: isTop ? `0 0 20px ${item.color}50` : "none",
                    },
                  }}
                  transition={{
                    type: "spring",
                    stiffness: 400,
                    damping: 20,
                  }}
                >
                  {isTop && (
                    <>
                      {item.icon}
                      <span className="font-bold tracking-wide">{item.name}</span>
                    </>
                  )}
                </motion.div>
              );
            })}
          </motion.div>
        ))}
      </div>
    );
  }
);

