          {/* Progress Bar */}
          <div 
            className="absolute bottom-0 left-0 h-1 bg-black/10 rounded-b-2xl"
            style={{
              width: '100%',
              animation: `toast-progress ${duration}ms linear forwards`
            }}
          />
        </div>
        );
        });

